**Three-phase approach**:
1. Find middle (slow/fast).
2. Reverse the second half.
3. Merge alternately.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function reorderDeliveryFeed(head) {
  if (!head || !head.next) return head;
  // 1. middle
  let slow = head, fast = head;
  while (fast.next && fast.next.next) { slow = slow.next; fast = fast.next.next; }
  // 2. reverse second half
  let prev = null, curr = slow.next;
  slow.next = null;
  while (curr) { const n = curr.next; curr.next = prev; prev = curr; curr = n; }
  // 3. merge
  let first = head, second = prev;
  while (second) {
    const t1 = first.next, t2 = second.next;
    first.next = second;
    second.next = t1;
    first = t1; second = t2;
  }
  return head;
}

function solve(arr) {
  return listToArray(reorderDeliveryFeed(arrayToList(arr)));
}
