editorial:
**Floyd's cycle finding — second phase**:
After slow/fast meet inside the cycle, math shows the distance from the head to the cycle entry equals the distance from the meeting point to the cycle entry (modulo cycle length). So move one pointer back to head and step both 1 at a time; they meet at the entry.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToListWithCycle(arr, pos) {
  if (arr.length === 0) return null;
  const nodes = arr.map(v => new ListNode(v));
  for (let i = 0; i < nodes.length - 1; i++) nodes[i].next = nodes[i + 1];
  if (pos >= 0 && pos < nodes.length) nodes[nodes.length - 1].next = nodes[pos];
  return nodes[0];
}

function cycleEntryPoint(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) {
      let p = head;
      while (p !== slow) { p = p.next; slow = slow.next; }
      return p.val;
    }
  }
  return null;
}

function solve(arr, pos) {
  return cycleEntryPoint(arrayToListWithCycle(arr, pos));
}
```

**Time**: O(n). **Space**: O(1).

