**Idea — top-down merge sort on linked list**:
1. Find the middle (slow/fast), split into two halves.
2. Recursively sort each half.
3. Merge.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function merge(a, b) {
  const dummy = new ListNode();
  let t = dummy;
  while (a && b) {
    if (a.val <= b.val) { t.next = a; a = a.next; }
    else { t.next = b; b = b.next; }
    t = t.next;
  }
  t.next = a || b;
  return dummy.next;
}

function sortFulfillmentList(head) {
  if (!head || !head.next) return head;
  // split
  let slow = head, fast = head, prev = null;
  while (fast && fast.next) { prev = slow; slow = slow.next; fast = fast.next.next; }
  prev.next = null;
  const left = sortFulfillmentList(head);
  const right = sortFulfillmentList(slow);
  return merge(left, right);
}

function solve(arr) {
  return listToArray(sortFulfillmentList(arrayToList(arr)));
}
```

**Time**: O(n log n). **Space**: O(log n) recursion stack — true O(1) requires the iterative bottom-up variant.
